def write_log(text):
    log_box.config(state=tk.NORMAL)
    log_box.insert(tk.END, text)
    log_box.see(tk.END)
    root.update()
    log_box.config(state=tk.DISABLED)


def show_qr_in_log():
    """在日志框下方显示收款码图片和提示文字"""
    try:
        img_data = base64.b64decode(QR_B64)
        img = Image.open(io.BytesIO(img_data))
        img = img.resize((220, 220), Image.LANCZOS)
        photo = ImageTk.PhotoImage(img)

        # 保持引用，防止被 GC
        qr_label.config(image=photo)
        qr_label.image = photo
        qr_tip_label.config(text="若软件对您有帮助，还请支持作者！")
    except Exception as e:
        qr_tip_label.config(text=f"收款码加载失败：{e}")


# =========================================================
# 核心处理逻辑（在子线程中执行，避免 GUI 卡死）
# =========================================================

def _do_process(source_folder, word_path,
                pdf_width, image_width,
                crop_left, crop_right, crop_top, crop_bottom,
                img_crop_left, img_crop_right, img_crop_top, img_crop_bottom,
                scale, quality):

    # DOC 转 DOCX
    if word_path.lower().endswith(".doc"):
        new_docx = convert_doc_to_docx(word_path, write_log)
        if not new_docx:
            return
        word_path = new_docx

    write_log("=" * 50 + "\n")
    write_log("开始处理...\n")
    write_log("=" * 50 + "\n\n")

    # 打开Word
    try:
        doc = Document(word_path)
    except Exception as e:
        messagebox.showerror("错误", f"Word打开失败：{e}")
        return

    # 获取文件
    pdf_files = get_files_by_ext(source_folder, ".pdf")
    image_files = get_files_by_ext(source_folder, IMAGE_EXTENSIONS)

    word_data_files = [
        f for f in os.listdir(source_folder)
        if f.lower().endswith((".doc", ".docx", ".rtf"))
        and not f.startswith("~")
    ]

    # 同名文件择优：PDF > DOCX > DOC > RTF
    preferred_names = set(os.path.splitext(f)[0] for f in pdf_files)
    filtered_word_data_files = []
    chosen_names = set(preferred_names)
    for ext in [".docx", ".doc", ".rtf"]:
        for f in word_data_files:
            name = os.path.splitext(f)[0]
            if name in chosen_names:
                continue
            if f.lower().endswith(ext):
                filtered_word_data_files.append(f)
                chosen_names.add(name)
    word_data_files = filtered_word_data_files

    # 使用系统临时目录存放中间图片（避免中文桌面路径问题）
    tmp_dir = tempfile.mkdtemp(prefix="washa_tmp_")

    # =====================================================
    # 处理 PDF
    # =====================================================
    for pdf_file in pdf_files:
        write_log(f"\n===== PDF：{pdf_file} =====\n")
        pdf_path_item = os.path.join(source_folder, pdf_file)
        file_name_without_ext = os.path.splitext(pdf_file)[0]
        tmp_image = os.path.join(tmp_dir, f"tmp_{file_name_without_ext}.png")

        success = pdf_to_first_page_image(pdf_path_item, tmp_image, write_log, scale=scale)
        if success:
            cropped_image = crop_image(tmp_image, crop_left, crop_right, crop_top, crop_bottom, write_log)
            update_word_table(doc, file_name_without_ext, cropped_image, write_log, pdf_width, image_width, is_pdf=True, quality=quality)
            update_word_paragraphs(doc, file_name_without_ext, cropped_image, write_log, pdf_width, image_width, is_pdf=True, quality=quality)
            try:
                if os.path.exists(tmp_image):
                    os.remove(tmp_image)
                if cropped_image != tmp_image and os.path.exists(cropped_image):
                    os.remove(cropped_image)
            except Exception as e:
                write_log(f"⚠️ 清理临时文件时出错：{e}\n")

    # =====================================================
    # 处理 Word 数据文件（优先级：DOCX→DOC→RTF）
    # =====================================================
    word_data_files.sort(
        key=lambda f: (
            0 if f.lower().endswith(".docx") else
            1 if f.lower().endswith(".doc") else
            2
        )
    )
    for word_file in word_data_files:
        if os.path.abspath(os.path.join(source_folder, word_file)) == os.path.abspath(word_path):
            continue
        write_log(f"\n===== Word：{word_file} =====\n")
        full_path = os.path.join(source_folder, word_file)
        name_without_ext = os.path.splitext(word_file)[0]
        tmp_image = os.path.join(tmp_dir, f"tmp_word_{name_without_ext}.png")

        success = word_first_page_to_image(full_path, tmp_image, write_log)
        if success:
            cropped_image = crop_image(tmp_image, crop_left, crop_right, crop_top, crop_bottom, write_log)
            update_word_table(doc, name_without_ext, cropped_image, write_log, pdf_width, image_width, is_pdf=True, quality=quality)
            update_word_paragraphs(doc, name_without_ext, cropped_image, write_log, pdf_width, image_width, is_pdf=True, quality=quality)
            try:
                if os.path.exists(tmp_image):
                    os.remove(tmp_image)
                if cropped_image != tmp_image and os.path.exists(cropped_image):
                    os.remove(cropped_image)
            except Exception as e:
                write_log(f"⚠️ 清理临时文件时出错：{e}\n")

    # =====================================================
    # 处理图片（最后）
    # =====================================================
    for image_file in image_files:
        write_log(f"\n===== 图片：{image_file} =====\n")
        image_path = os.path.join(source_folder, image_file)
        file_name_without_ext = os.path.splitext(image_file)[0]

        cropped_image = crop_image(image_path, img_crop_left, img_crop_right, img_crop_top, img_crop_bottom, write_log)
        update_word_table(doc, file_name_without_ext, cropped_image, write_log, pdf_width, image_width, is_pdf=False, quality=quality)
        update_word_paragraphs(doc, file_name_without_ext, cropped_image, write_log, pdf_width, image_width, is_pdf=False, quality=quality)
        try:
            if cropped_image != image_path and os.path.exists(cropped_image):
                os.remove(cropped_image)
        except Exception as e:
            write_log(f"⚠️ 清理临时文件时出错：{e}\n")

    # 保存
    try:
        doc.save(word_path)
    except Exception as e:
        messagebox.showerror("错误", f"保存失败：{e}")
        return

    write_log("\n")
    write_log("=" * 50 + "\n")
    write_log("✅ 全部处理完成\n")
    write_log("=" * 50 + "\n")

    # 清理临时目录
    try:
        shutil.rmtree(tmp_dir, ignore_errors=True)
    except Exception:
        pass

    # 完成后显示收款码
    root.after(0, show_qr_in_log)

    open_file(word_path)
    messagebox.showinfo("完成", "全部文件已插入完成！")


def start_process():
    source_folder = entry_folder.get().strip()
    word_path = entry_word.get().strip()

    # 读取宽度
    try:
        pdf_width = float(entry_pdf_width.get())
        image_width = float(entry_image_width.get())
    except Exception:
        messagebox.showerror("错误", "PDF宽度 / 图片宽度 必须填写数字")
        return

    try:
        crop_left       = float(entry_crop_left.get())
        crop_right      = float(entry_crop_right.get())
        crop_top        = float(entry_crop_top.get())
        crop_bottom     = float(entry_crop_bottom.get())
        img_crop_left   = float(entry_img_crop_left.get())
        img_crop_right  = float(entry_img_crop_right.get())
        img_crop_top    = float(entry_img_crop_top.get())
        img_crop_bottom = float(entry_img_crop_bottom.get())
        scale           = float(entry_scale.get())
        quality         = int(entry_quality.get())
    except Exception:
        messagebox.showerror("错误", "裁边比例 / 缩放倍率 必须填写数字")
        return

    if not source_folder or not word_path:
        messagebox.showerror("错误", "请选择文件夹和Word文件")
        return
    if not os.path.exists(source_folder):
        messagebox.showerror("错误", "文件夹不存在")
        return
    if not os.path.exists(word_path):
        messagebox.showerror("错误", "Word文件不存在")
        return

    # 清空日志
    log_box.config(state=tk.NORMAL)
    log_box.delete(1.0, tk.END)
    log_box.config(state=tk.DISABLED)

    # 重置收款码区域
    qr_label.config(image="")
    qr_tip_label.config(text="")

    # 在子线程中执行（避免 GUI 卡死）
    threading.Thread(
        target=_do_process,
        args=(source_folder, word_path,
              pdf_width, image_width,
              crop_left, crop_right, crop_top, crop_bottom,
              img_crop_left, img_crop_right, img_crop_top, img_crop_bottom,
              scale, quality),
        daemon=True
    ).start()


