ENTRY_KW = dict(font=(FONT_FAM, 11), relief="flat", bg=CARD_BG, fg=TEXT_DARK,
                bd=0, highlightthickness=1, highlightbackground=SILVER)


def _make_entry(parent, width, default=""):
    e = tk.Entry(parent, width=width, **ENTRY_KW)
    e.pack(side="left", ipady=4)
    e.insert(0, default)
    return e


def _make_crop_group(parent, labels_dflts):
    entries = {}
    for label, varname, dflt in labels_dflts:
        ttk.Label(parent, text=label, style="Size.TLabel").pack(side="left")
        e = _make_entry(parent, 5, dflt)
        entries[varname] = e
        ttk.Label(parent, text="%", style="Size.TLabel").pack(side="left", padx=(2, 8))
    return entries


def _make_file_row(parent, label_text, btn_text, btn_cmd):
    row = ttk.Frame(parent, style="Card.TFrame")
    row.pack(fill="x", padx=10, pady=(8, 0))
    ttk.Label(row, text=label_text, style="Field.TLabel", width=15).pack(side="left")
    e = tk.Entry(row, **ENTRY_KW)
    e.pack(side="left", fill="x", expand=True, ipady=4, padx=(4, 8))
    btn = ttk.Button(row, text=btn_text, style="Browse.TButton", command=btn_cmd)
    btn.pack(side="left")
    return e


